                "type": "string",
                "pattern": "^IGF[a-zA-Z0-9-_]+$"
            },
            "Sample_Name": {
                "type": "string",
                "pattern": "^[a-zA-Z0-9-]+$"
            },
            "Sample_Project": {
                "type": "string",
                "pattern": "^IGF[a-zA-Z0-9-_]+$"
            },
            "I7_Index_ID": {
